-- Case 003: MATCH_RECOGNIZE funnel pattern with nested input and post-filtering
WITH filtered_events AS(SELECT user_id,session_id,event_time,LOWER(event_name) AS event_name,page_url,TRY_TO_DECIMAL(properties:amount::STRING,18,2) AS amount,properties:currency::STRING AS currency_code,properties:error_code::STRING AS error_code FROM WEB.CLICKSTREAM_EVENTS WHERE event_time >= DATEADD( 'day',-14,CURRENT_TIMESTAMP()) AND user_id IS NOT NULL),matches AS(SELECT * FROM filtered_events MATCH_RECOGNIZE(PARTITION BY user_id,session_id ORDER BY event_time MEASURES MATCH_NUMBER() AS funnel_match_number,FIRST(login.event_time) AS login_at,LAST(success.event_time) AS success_at,COUNT(browse.*) AS browse_count,MAX(payment.amount) AS max_payment_amount,ARRAY_AGG(CLASSIFIER()) WITHIN GROUP(ORDER BY MATCH_SEQUENCE_NUMBER()) AS classifier_path ONE ROW PER MATCH AFTER MATCH SKIP TO NEXT ROW PATTERN(login browse{1,5} checkout? payment failure* success) DEFINE login AS event_name IN( 'login', 'sign_in'),browse AS event_name IN( 'view_item', 'search', 'category_view'),checkout AS event_name = 'checkout_started',payment AS event_name IN( 'payment_submitted', 'payment_retry') AND amount IS NOT NULL,failure AS event_name = 'payment_failed' AND error_code IS NOT NULL,success AS event_name IN( 'order_completed', 'subscription_started'))) SELECT user_id,session_id,funnel_match_number,login_at,success_at,DATEDIFF( 'second',login_at,success_at) AS seconds_to_success,browse_count,max_payment_amount,classifier_path,ROW_NUMBER() OVER(PARTITION BY user_id ORDER BY success_at DESC,funnel_match_number DESC) AS latest_success_rank FROM matches QUALIFY latest_success_rank <= 3 ORDER BY user_id,latest_success_rank;
